import React, { FC } from 'react';
import SptLink, { SptLinkType } from '../SptLink';
import SptIcon, { SptIconProps } from '../SptIcon';
import { SptComponentProvider } from '../Provider';

export interface SptOuterLinkProps {
    type?: SptLinkType;
    to: string;
    text: string;
    sptIconProps?: SptIconProps;
}

const SpotterOuterLinkBase: FC<SptOuterLinkProps> = ({ type = 'new', text, to, sptIconProps }) => (
    <span>
        {text ? (
            <SptLink type={type} to={to}>
                {text}
                <SptIcon {...sptIconProps} color="var(--color-primary)" type="sptfont-link" />
            </SptLink>
        ) : (
            '-'
        )}
    </span>
);

/**
 * 跳转外部地址，带Icon版本的SpotterLink
 * @param props
 * @returns
 */
const SptOuterLink: FC<SptOuterLinkProps> = (props) => {
    return (
        <SptComponentProvider>
            <SpotterOuterLinkBase {...props} />
        </SptComponentProvider>
    );
};

export default SptOuterLink;
